package admission

import (
	"slices"

	"github.com/formancehq/ledger/v3/internal/domain"
	"github.com/formancehq/ledger/v3/internal/proto/commonpb"
	"github.com/formancehq/ledger/v3/internal/proto/servicepb"
)

// extractSkippableReasonsFromApply pulls and validates the top-level
// `skippable_reasons` list off a LedgerApplyRequest. Returns the typed
// enum slice ready to assign onto raftcmdpb.Order.SkippableReasons, or a
// BusinessError-wrapped ErrInvalidSkippableReason when any entry is
// rejected.
//
// The per-action business whitelist is generated by protoc-gen-skippable
// from the (allowed_skippable_reasons) annotations on LedgerAction's
// oneof cases (see misc/proto/bucket.proto). To extend the whitelist,
// edit the .proto annotation and regenerate — this Go layer stays as-is.
//
// Validation rules:
//   - Empty lists pass through as no-op (skip disabled).
//   - UNSPECIFIED is always rejected (caller forgot to set the enum value).
//   - Each entry must appear in the action-specific whitelist.
//   - A non-empty list on an action that does not opt into skip is
//     rejected — silently dropping the intent would surprise the caller.
func extractSkippableReasonsFromApply(apply *servicepb.LedgerApplyRequest) ([]commonpb.ErrorReason, error) {
	reasons := apply.GetSkippableReasons()
	if len(reasons) == 0 {
		return nil, nil
	}

	allowed := servicepb.SkippableReasonsForLedgerAction(apply.GetAction())
	if len(allowed) == 0 {
		// Either the action is nil / unknown, or the .proto declares
		// no (allowed_skippable_reasons) for its oneof case. Reject
		// rather than silently drop the caller's intent.
		return nil, &domain.BusinessError{Err: &domain.ErrInvalidSkippableReason{Provided: reasons[0]}}
	}

	for _, r := range reasons {
		if r == commonpb.ErrorReason_ERROR_REASON_UNSPECIFIED {
			return nil, &domain.BusinessError{Err: &domain.ErrInvalidSkippableReason{Provided: r}}
		}

		if !slices.Contains(allowed, r) {
			return nil, &domain.BusinessError{Err: &domain.ErrInvalidSkippableReason{Provided: r}}
		}
	}

	return reasons, nil
}
